class Solution:
    def uncommonFromSentences(self, s1: str, s2: str) -> List[str]:
        words1 = s1.split()
        words2 = s2.split()
        counts = {}
        for word in words1:
            if word in counts:
                counts[word] += 1
            else:
                counts[word] = 1
        for word in words2:
            if word in counts:
                counts[word] += 1
            else:
                counts[word] = 1
        return [word for word, count in counts.items() if count == 1]
